(function () {
  function applyRosterOnlyMode() {
    if (!document.body || document.body.id !== 'body_options_07') return;
    var root = document.getElementById('MFLroster');
    if (!root) return;

    document.body.classList.add('ups-roster-only-mode');

    var tradeBar = document.getElementById('rosterTradeLinkDIV');
    if (tradeBar) {
      tradeBar.querySelectorAll('input[type="submit"]').forEach(function (btn) {
        btn.remove();
      });
      var appendRos = tradeBar.querySelector('#appendRos');
      if (appendRos) appendRos.remove();
      var deadline = tradeBar.querySelector('#deadlinePassed');
      if (deadline) deadline.remove();
      tradeBar.style.display = 'none';
    }

    var messageBox = document.getElementById('messageBoxDIV');
    if (messageBox) messageBox.remove();

    var proposeTradeButtons = document.getElementById('propseTradeButtonDIV');
    if (proposeTradeButtons) proposeTradeButtons.remove();

    root.querySelectorAll('.roster_assets').forEach(function (tbl) {
      tbl.remove();
    });

    root.querySelectorAll('#tradeViewTab,#allViewTab,#rosterViewTab').forEach(function (el) {
      el.remove();
    });

    if (typeof rosterViewClickFunction === 'function') {
      try { rosterViewClickFunction(); } catch (e) {}
    }
  }

  function initRosterOnlyPatch() {
    applyRosterOnlyMode();
    var obsRoot = document.getElementById('options_07') || document.body;
    if (!obsRoot || obsRoot.__upsRosterOnlyPatchObserver) return;
    var observer = new MutationObserver(function () {
      applyRosterOnlyMode();
    });
    observer.observe(obsRoot, { childList: true, subtree: true });
    obsRoot.__upsRosterOnlyPatchObserver = observer;
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initRosterOnlyPatch);
  } else {
    initRosterOnlyPatch();
  }
})();
